section.para:
			The composed gazetteer then answers lookups from both sides: the
			customer file wins for its own names, and the suppressed city is gone
			from every query.

Gazetteer base = BundledGazetteer.getInstance();
Gazetteer customer = UserGazetteer.load(Path.of("customer_places.txt"), "customer");
List<Suppression> rules = UserGazetteer.loadSuppressions(Path.of("suppress.txt"));
Gazetteer gazetteer = new OverlayGazetteer(base, customer, rules);

GazetteerEntry plant = gazetteer.lookup("Plant 3").get(0);
// plant.name() = "Acme Plant 3", plant.source() = "customer"
// plant.attributes().get("address").value() = "123 Main St, Atlanta GA 30303"

gazetteer.lookup("Mobile");    // empty: the Alabama city is suppressed
gazetteer.lookup("Tokyo");     // unaffected base entries stay visible

			The additions side does not have to be a file: any
			Gazetteer implementation serves, so entries ingested from
			a database or fetched from a service compose the same way.

			The following complete implementation serves an application-internal
			store from two maps. It lives in the project's test sources as
			CrmGazetteer, ready to copy, and
			CustomGazetteerExampleTest asserts the behavior shown
			here.

final class CrmGazetteer implements Gazetteer {

  static final String SOURCE = "crm";

  private final Map<String, GazetteerEntry> byName;
  private final Map<String, GazetteerEntry> byId;

  CrmGazetteer(List<GazetteerEntry> entries) {
    if (entries == null) {
      throw new IllegalArgumentException("entries must not be null");
    }
    final Map<String, GazetteerEntry> names = new HashMap<>();
    final Map<String, GazetteerEntry> ids = new HashMap<>();
    for (final GazetteerEntry entry : entries) {
      names.put(entry.name().toLowerCase(Locale.ROOT), entry);
      ids.put(entry.recordId(), entry);
    }
    this.byName = Map.copyOf(names);
    this.byId = Map.copyOf(ids);
  }

  @Override
  public List<GazetteerEntry> lookup(CharSequence name) {
    if (name == null) {
      throw new IllegalArgumentException("name must not be null");
    }
    final GazetteerEntry found = byName.get(name.toString().toLowerCase(Locale.ROOT));
    return found == null ? List.of() : List.of(found);
  }

  @Override
  public Optional<GazetteerEntry> byId(String source, String recordId) {
    if (source == null || recordId == null) {
      throw new IllegalArgumentException("source and recordId must not be null");
    }
    return SOURCE.equals(source) ? Optional.ofNullable(byId.get(recordId)) : Optional.empty();
  }

  @Override
  public Optional<GazetteerEntry> byRegion(String isoCountryCode) {
    if (isoCountryCode == null || isoCountryCode.length() != 2
        || !isAsciiLetter(isoCountryCode.charAt(0)) || !isAsciiLetter(isoCountryCode.charAt(1))) {
      throw new IllegalArgumentException(
          "isoCountryCode must be two ASCII letters, got: " + isoCountryCode);
    }
    final String code = isoCountryCode.toUpperCase(Locale.ROOT);
    GazetteerEntry best = null;
    for (final GazetteerEntry entry : byId.values()) {
      if (code.equals(entry.countryCode())
          && (best == null || entry.population() > best.population())) {
        best = entry;
      }
    }
    return Optional.ofNullable(best);
  }

  @Override
  public Set<String> sources() {
    return Set.of(SOURCE);
  }

  private static boolean isAsciiLetter(char c) {
    return (c >= 'A' && c <= 'Z') || (c >= 'a' && c <= 'z');
  }
}

			Composed over the bundled base, the custom entries answer their own
			names while the base keeps answering everything else.

Gazetteer crm = new CrmGazetteer(List.of(new GazetteerEntry("crm", "cust-1", "Acme Plant 3",
    List.of(), new GeoPoint(33.75, -84.39), "US", List.of(), 0L,
    GazetteerEntry.FEATURE_CLASS_POI, Map.of())));
Gazetteer gazetteer = new OverlayGazetteer(BundledGazetteer.getInstance(), crm, List.of());

GazetteerEntry plant = gazetteer.lookup("Acme Plant 3").get(0);
// plant.source() = "crm", plant.location() = new GeoPoint(33.75, -84.39)
gazetteer.lookup("Tokyo");   // the base still answers everything else

			A Geocoder turns location mention spans into
			GeoResolution records against a Gazetteer.
			PopulationPriorGeocoder picks the most populous candidate for
			each mention; unresolved mentions are omitted.
			GeocoderUsageExampleTest asserts the workflow shown here.

Geocoder geocoder = new PopulationPriorGeocoder(gazetteer);
String text = "She grew up in Springfield.";
Span mention = new Span(text.indexOf("Springfield"),
    text.indexOf("Springfield") + "Springfield".length());

List<GeoResolution> resolutions = geocoder.resolve(text, List.of(mention));
// resolutions.get(0).entry() is the most populous Springfield
